const normalizeGuideImagePath = (url) => {
  const path = String(url || '').split('?')[0]
  const staticIndex = path.indexOf('/static/')

  return staticIndex >= 0 ? path.slice(staticIndex) : path
}

const getGuideImageSize = (url) => GUIDE_IMAGE_SIZES[normalizeGuideImagePath(url)] || null

module.exports = {
  GUIDE_IMAGE_SIZES,
  getGuideImageSize
}
